#include <bits/stdc++.h>
using namespace std;

const int N=5e3+5;
const long long INF=0x3f3f3f3f3f3f3f3f;

struct Edge{
    int to,val;
};

int n,m,sum[N];
long long dist[N];
bool init[N];
vector<Edge> g[N];

bool SPFA(int st){
    dist[st]=0;
    queue<int> q;
    q.push(st),init[st]=1;
    while(q.size()){
        int x=q.front();
        q.pop(),init[x]=0;
        for(Edge y:g[x])
            if(dist[y.to]>dist[x]+y.val){
                dist[y.to]=dist[x]+y.val;
                if(!init[y.to])
                    q.push(y.to),init[y.to]=1;
                if(++sum[y.to]==n+3)
                    return 0;
            }
    }
    return 1;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=0,u,v,w;i<m;i++){
        scanf("%d%d%d",&v,&u,&w);
        g[u].push_back({v,w});
    }
    memset(dist,0x3f,sizeof(dist));
    for(int i=1;i<=n;i++)
        if(dist[i]==INF)
            if(!SPFA(i)){
                printf("NO");
                return 0;
            }
    for(int i=1;i<=n;i++)
        printf("%lld ",dist[i]);
    return 0;
}
